import{_ as t,o,c as r,ag as a}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"Brand","description":"","frontmatter":{},"headers":[],"relativePath":"brand.md","filePath":"brand.md","lastUpdated":1777844625000}'),d={name:"brand.md"};function n(i,e,s,c,h,l){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="brand" tabindex="-1">Brand <a class="header-anchor" href="#brand" aria-label="Permalink to &quot;Brand&quot;">​</a></h1><p><strong>Date locked:</strong> 2026-05-03 <strong>Decision reference:</strong> <code>docs/marketing/2026-05-03-branding-decision.md</code></p><p>A one-page reference for anyone writing public-facing copy, talks, slides, or third-party documentation about this project. Read once; carry forward.</p><h2 id="names" tabindex="-1">Names <a class="header-anchor" href="#names" aria-label="Permalink to &quot;Names&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Name</th><th>Use it as</th></tr></thead><tbody><tr><td>Protocol noun</td><td><strong>QKB</strong> (Qualified Key Binding)</td><td>The noun. The thing that ships at V1. The name in code, contracts, packages, specs, CLI, ceremony commands.</td></tr><tr><td>Public-facing descriptor</td><td><strong>zk-QES</strong></td><td>The descriptor. What QKB <em>is</em> in two seconds for an outside reader. Use in opening lines, taglines, HN titles, conference abstracts.</td></tr><tr><td>Project umbrella</td><td><strong>Identity Escrow</strong></td><td>The org-level name. The research line. The thing the .org domain points at.</td></tr><tr><td>Phase 2 design line (parked)</td><td><strong>QIE</strong> (Qualified Identity Escrow)</td><td>Internal codename only. Not for public copy until QIE either ships or is formally killed.</td></tr></tbody></table><h2 id="the-split-explained-once" tabindex="-1">The split, explained once <a class="header-anchor" href="#the-split-explained-once" aria-label="Permalink to &quot;The split, explained once&quot;">​</a></h2><p><code>QKB</code> is the codename. It is structurally locked into shipped artifacts (<code>@qkb/*</code> packages, <code>QKBRegistry*</code> contracts, <code>QKBPresentationV5.circom</code>, <code>qkb</code> CLI, <code>qkb-v5.r1cs</code>). Renaming any of that surface mid-ceremony would be high-cost for zero functional gain. So we keep <code>QKB</code> as the working name.</p><p><code>zk-QES</code> is the descriptor — &quot;zero-knowledge proof of a qualified electronic signature, in the eIDAS sense.&quot; It parses instantly for the audience this project is aimed at (PSE, 0xPARC, Mopro, Anon Aadhaar, ZK research). We use it as the descriptor any time we need outside legibility.</p><p><code>Identity Escrow</code> is the project umbrella. It does not refer to a specific contract feature; it refers to a property that any state-issued credential exhibits: the issuing authority retains the ability to identify a holder under lawful process. V1 (QKB) already exhibits this property by virtue of the Diia QES anchor. Future iterations may extend toward fuller escrow constructions, but nothing is promised on a timeline.</p><h2 id="how-to-write-about-the-project" tabindex="-1">How to write about the project <a class="header-anchor" href="#how-to-write-about-the-project" aria-label="Permalink to &quot;How to write about the project&quot;">​</a></h2><p><strong>Do:</strong></p><ul><li>Lead with the descriptor: &quot;QKB is a zero-knowledge protocol over qualified electronic signatures (zk-QES).&quot;</li><li>Use <code>QKB</code> in install commands, code references, contract addresses, ceremony command paths.</li><li>Use <code>Identity Escrow</code> only when referring to the project as a whole, not to V1&#39;s feature set.</li></ul><p><strong>Don&#39;t:</strong></p><ul><li>Don&#39;t market <code>QIE</code> as a near-term feature; it is parked.</li><li>Don&#39;t claim escrow as a V1 feature; V1 ships pure binding registration.</li><li>Don&#39;t introduce a fourth name. Three is enough.</li></ul><h2 id="domains" tabindex="-1">Domains <a class="header-anchor" href="#domains" aria-label="Permalink to &quot;Domains&quot;">​</a></h2><p>The public-facing surface uses three subdomains under <code>zkqes.org</code>. Locked 2026-05-03.</p><table tabindex="0"><thead><tr><th>Subdomain</th><th>Purpose</th><th>Lifecycle</th></tr></thead><tbody><tr><td><code>zkqes.org</code> (root)</td><td>Pre-ceremony hero + ceremony recruitment CTA + three contribution paths (snarkjs local / VPS / Fly launcher)</td><td>Live pre-recruitment; persists post-launch as the project landing</td></tr><tr><td><code>app.zkqes.org</code></td><td>The actual register flow — <code>/v5/registerV5</code> + <code>/account/rotate</code>. Hosts the SPA. End users come here only after Phase B ceremony completes + Sepolia E2E §9.4 green</td><td>Live post-ceremony</td></tr><tr><td><code>docs.zkqes.org</code></td><td>VitePress-rendered docs from the <code>docs/</code> tree — install instructions, specs, ceremony attestations, SDK reference, this BRAND.md</td><td>Live pre-recruitment</td></tr><tr><td><code>prove.zkqes.org</code></td><td>Ceremony coordinator (R2-backed status feed + manifest hosting) — successor to <code>prove.identityescrow.org</code></td><td>Live post-DNS migration</td></tr><tr><td><code>identityescrow.org</code></td><td>301 alias to <code>zkqes.org</code></td><td>Permanent backwards-compat</td></tr></tbody></table><p>The split exists because the three audiences are distinct: ceremony contributors (zkqes.org root), end users registering with their QES (app.zkqes.org, post-launch), and developers / integrators / researchers (docs.zkqes.org). Surfacing all three on one page would mute the call-to-action that matters at the current lifecycle stage.</p><h2 id="defensive-registrations" tabindex="-1">Defensive registrations <a class="header-anchor" href="#defensive-registrations" aria-label="Permalink to &quot;Defensive registrations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Asset</th><th>Status</th><th>Action</th></tr></thead><tbody><tr><td><code>zkqes.org</code></td><td>Live, canonical</td><td>Keep — primary public domain</td></tr><tr><td><code>identityescrow.org</code></td><td>Live</td><td>301 alias → <code>zkqes.org</code></td></tr><tr><td><code>identityescroworg</code> (GitHub)</td><td>Live</td><td>Keep — repo name (renaming breaks every link in already-published specs and orchestration plans)</td></tr><tr><td><code>zkqes.com</code></td><td>Open call</td><td>Recommended defensive buy + 301 → <code>zkqes.org</code></td></tr><tr><td><code>@qkb</code> (npm)</td><td>Live, in use</td><td>Keep — protocol-noun scope</td></tr><tr><td><code>@zkqes</code> (npm)</td><td>Open call</td><td>Recommended defensive squat (no publishes)</td></tr></tbody></table><h2 id="when-this-document-changes" tabindex="-1">When this document changes <a class="header-anchor" href="#when-this-document-changes" aria-label="Permalink to &quot;When this document changes&quot;">​</a></h2><p>This brand split is intentionally cheap to reverse. If founder later decides to flip the public noun from <code>QKB</code> to <code>zk-QES</code>, <code>zkqes.org</code> and <code>@zkqes</code> are already in hand and the flip is a marketing sweep rather than a code rename. Do not edit this document without founder sign-off; the cost of churn here is paid in audience confusion.</p>',22)])])}const m=t(d,[["render",n]]);export{u as __pageData,m as default};
